fn is_prime(n: Int64) -> Bool {
    if n <= 1 { return false }
    if n <= 3 { return true }
    if n % 2 == 0 || n % 3 == 0 { return false }
    var i = 5
    while i * i <= n {
        if n % i == 0 || n % (i + 2) == 0 {
            return false
        }
        i += 6
    }
    true
}

fn solve(nums : Array(Int64)) : Int64 {
    var total_cost: Int64 = 0

    for (i, &n) in nums.with_indices() {
        if i % 2 == 0 {
            // Even index: Must be prime
            if is_prime(n) {
                // Already prime
                continue
            } else {
                // Find the smallest prime P >= n
                var target: Int64 = n
                while !is_prime(target) {
                    target += 1
                }
                total_cost += (target - n)
            }
