                continue
            } else {
                // n is prime. Find the smallest non-prime C >= n.
                var target: Int64
                if n == 2 {
                    // 2 -> 4 (smallest non-prime >= 2)
                    target = 4
                } else {
                    // For any prime n > 2 (odd), n+1 is an even number > 2, so it is composite.
                    target = n + 1
                }
                total_cost += (target - n)
            }
        }
    }

    return total_cost
}

